def split_words(txt):
    '''
    Given a string of words, return a list of words split on whitespace, 
    if no whitespaces exists in the text, you should split on commas ','; 
    if no commas exist, return the number of lower-case letters with odd order 
    in the alphabet (ord('a') = 0, ord('b') = 1, ... ord('z') = 25).

    Examples:
    split_words("Hello world!") ➞ ["Hello", "world!"]
    split_words("Hello,world!") ➞ ["Hello", "world!"]
    split_words("abcdef") ➞ 3 
    '''
    # Check if there are whitespace characters
    if ' ' in txt:
        return txt.split()

    # Check if there are commas and no whitespace
    elif ',' in txt:
        return txt.split(',')

    # If neither whitespace nor commas are present, count lowercase letters in odd positions
    else:
        return sum(1 for char in txt if char.islower() and (ord(char) % 2 == 1))

# Examples
