def split_words(txt):
    '''
    Given a string of words, return a list of words split on whitespace. 
    If no whitespaces exist in the text, split on hyphens or colons. 
    If neither whitespace nor hyphens or colons exist, return the total count of lowercase letters 
    (ord('a') = 0, ord('b') = 1, ... ord('z') = 25).

    Examples:
    split_words("Hello world!") ➞ ["Hello", "world!"]
    split_words("Hello-world!") ➞ ["Hello", "world!"]
    split_words("Hello:world!") ➞ ["Hello", "world!"]
    split_words("abcdef") ➞ 3 
    '''
    if ' ' in txt:
        return txt.split()
    elif '-' in txt:
        return txt.split('-')
    elif ':' in txt:
        return txt.split(':')
    else:
        return sum(1 for char in txt if char.islower())

# Examples
print(split_words("Hello world!"))  # ➞ ["Hello", "world!"]
print(split_words("Hello-world!"))   # ➞ ["Hello", "world!"]
print(split_words("Hello:world!"))   # ➞ ["Hello", "world!"]
print(split_words("abcdef"))         # ➞ 3
